# @njit(nogil=True)
def recall_by_all_study_positions(
    recall_by_first_study_position, # Integer array where rows correspond go trials and columns to recall positions. Non-zero values identify a (1-indexed) study position of the item recalled at that position.  
    presentations, # Integer array where rows correspond to trials and columns to study positions. Non-zero values identify the unique index of the item presented at that position.
    max_repeats=3 # Maximum number of times we will expect an item to be repeated in a study sequence.
    ):
    """
    Identifies all study positions of each item in a set of presentation sequences and sorts them by recall position.

    Returns a 3D array where the first dimension corresponds to the maximum number of times an item may have been repeated in a study sequence, the second to trial_index, and the third to recall position. Non-zero values along the first dimension identify the (1-index) study position(s) of the item recalled at that position.
    """
    
    trials_shape = np.shape(recall_by_first_study_position)
    result = np.zeros(
            (max_repeats, trials_shape[0], trials_shape[1]), dtype=np.int32)

    for trial_index in range(len(recall_by_first_study_position)):

        trial = recall_by_first_study_position[trial_index]
        presentation = presentations[trial_index]
        
        for recall_index in range(len(trial)):

            if trial[recall_index] == 0:
                continue

            presentation_positions = np.nonzero(
                presentation[trial[recall_index] - 1] == presentation)[0] + 1

            result[:len(presentation_positions), trial_index, recall_index] = presentation_positions

    return result

