import numpy as np
# from numba import njit

# @njit(fastmath=True, nogil=True)
def single_pres_crp(
    recalls, # Integer array where rows correspond to trials and columns to recall positions. Non-zero values are the (1-indexed) single study position of the item recalled at that position.
    list_length, # Number of item presentations in each study sequence
):
    """
    Assuming each study sequence has no more than a single presentation of each item, returns a vector of length `(list_length - 1) * 2 + 1` containing the recall rate for each lag from `-(list_length - 1)` to `list_length - 1`, with the recall rate for lag 0 in the middle of the vector and set to the value 0 despite being undefined (since lag transitions of 0 are not possible).
    """

    lag_range = list_length - 1
    total_actual_lags = np.zeros(lag_range * 2 + 1)
    total_possible_lags = np.zeros(lag_range * 2 + 1)
    terminus = np.sum(recalls != 0, axis=1)

    # compute actual serial lag b/t recalls
    actual_lags = recalls[:, 1:] - recalls[:, :-1]
    actual_lags += lag_range

    # tabulate bin totals for actual and possible lags
    for i in range(len(recalls)):
        possible_items = np.arange(list_length) + 1
        previous_item = 0

        for recall_index in range(terminus[i]):

            # track possible and actual lags
            if recall_index > 0:
                total_actual_lags[actual_lags[i, recall_index - 1]] += 1

                # exploit equivalence b/t item index and study position to track possible lags
                possible_lags = possible_items - previous_item
                possible_lags += lag_range
                total_possible_lags[possible_lags] += 1

            # update pool of possible items to exclude recalled item
            previous_item = recalls[i, recall_index]
            possible_items = possible_items[possible_items != previous_item]

    # small correction to avoid nans
    total_possible_lags[total_actual_lags == 0] += 1

    return total_actual_lags / total_possible_lags

