# @njit(nogil=True)
def multi_pres_crp(
    recalls, # Integer array where rows correspond to trials and columns to recall positions. Non-zero values identify a (1-indexed) study position of the item recalled at that position.
    presentations, # Integer array where rows correspond to trials and columns to study positions. Non-zero values identify the unique index of the item presented at that position.
    list_length # Number of item presentations in each study sequence
    ):
    """
    Calculate recall rate by lag across trials without the assumption that each study sequence has no more than a single presentation of each item. 
    
    Returns a vector of length `(list_length - 1) * 2 + 1` containing the recall rate for each lag indicing from `-(list_length - 1)` to `list_length - 1`, with the recall rate for lag 0 in the middle of the vector and set to the value 0 despite being undefined (since lag transitions of 0 are not possible). This function is slower than `single_pres_crp`, but it can be used with data where the single presentation assumption does not hold.
    """

    max_repeats = int(
        np.ceil(np.max(np.bincount(presentations.ravel()) / len(presentations)))
    )
    lag_range = list_length - 1
    total_actual_lags = np.zeros(lag_range * 2 + 1)
    total_possible_lags = np.zeros(lag_range * 2 + 1)
    terminus = np.sum(recalls != 0, axis=1)  # number of recalls per trial
    recall_by_study_position = recall_by_all_study_positions(
        recalls, presentations, max_repeats
    )

    for trial_index in range(len(recalls)):

        previous_item = 0
        item_count = np.max(presentations[trial_index])
        possible_items = np.arange(
            item_count,
            dtype=np.int32,
        )+1  # initial pool of possible recalls, 1-indexed
        possible_positions = np.zeros((item_count, max_repeats), dtype=np.int32)

        # we track possible positions using presentations and alt_presentations
        for item in range(item_count):
            pos = np.nonzero(presentations[trial_index] == item+1)[0] + 1
            possible_positions[item, :len(pos)] = pos

        for recall_index in range(terminus[trial_index]):

            current_item = presentations[trial_index][
                recalls[trial_index, recall_index] - 1
            ]

            # track possible and actual lags
            if recall_index > 0:

                # item indices don't help track lags anymore
                # so more complex calculation needed to identify possible lags given previous item
                current_index = np.nonzero(possible_items == current_item)[0]
                possible_lags = np.zeros(
                    (len(recall_by_study_position) ** 2, len(possible_items)),
                    dtype=np.int32,
                )

                index = 0
                for x in range(len(recall_by_study_position)):
                    for y in range(len(recall_by_study_position)):
                        if possible_positions[previous_item-1, y] > 0:

                            possible_lags[index] = (
                                possible_positions[possible_items-1, x]
                                - possible_positions[previous_item-1, y]
                            )

                            # if tracked position is 0, then we don't actually want to count it in our lags
                            possible_lags[index][
                                possible_positions[possible_items-1, x] == 0
                            ] = 0

                        index += 1
                possible_lags += lag_range

                total_actual_lags[possible_lags[:, current_index].flatten()] += 1
                total_possible_lags[possible_lags.flatten()] += 1

            # update pool to exclude recalled item (updated to still identify 1-indexed item)
            previous_item = current_item
            possible_items = possible_items[possible_items != previous_item]

    # small correction to avoid nans and commit to excluding multiply-tracked single presentations
    total_actual_lags[lag_range] = 0
    total_possible_lags[total_actual_lags == 0] += 1

    return total_actual_lags / total_possible_lags


