import matplotlib.pyplot as plt
from scipy.stats import bootstrap
import warnings

def plot_crp(
    datasets,  # sequence of strings identifying the relative paths of datasets to plot
    trial_masks, # vectors to filter datasets by
    labels=None,  # sequence of names for each dataset to use in the legend
    contrast_name=None,  # name of the contrast to use in the legend
    axis=None,  # `matplotlib` axis object to plot on
    max_lag=5,  # maximum lag to plot a recall rate for
    handle_repetitions=None,  # uses `multi_pres_crp` or `single_pres_crp` to calculate recall rates if boolean; otherwise tries to decide whether to use `multi_pres_crp` or `single_pres_crp` based on content of `presentations`
    mask=None,  # optional boolean array of same size as datasets' `presentations` that tracks lag-CRP in indices of `recalls` where corresponding index in mask is True
):
    """
    Generates a plot of the lag-CRP curve for the provided datasets and trial queries, optionally using the provided labels and contrast name in the legend. An axis object can be provided to plot on an existing figure. The maximum lag to plot can be specified, and the function can be told to use `multi_pres_crp` or `single_pres_crp` to calculate recall rates. If `mask` is provided, the lag-CRP to be plotted will be calculated only for the indices of `recalls` where the corresponding index in `mask` is True.
    """

    if axis is None:
        plt.figure()
        axis = plt.gca()

    if labels is None:
        labels = [""] * len(datasets)

    for data_index, data in enumerate(datasets):

        lag_interval = np.arange(-max_lag, max_lag + 1, dtype=np.int32)

        # generate and subset trials array and list of list_lengths based on trial_query
        trial_mask = trial_masks[data_index]
        trials = data["recalls"]
        presentations = data["pres_itemnos"]
        subjects = data["subject"].flatten()
        subject_crps = [] #np.zeros((len(np.unique(subjects)), len(lag_interval)))

        for subject_index, subject in enumerate(np.unique(subjects)):
            subject_specific_trial_mask = np.logical_and(
                subjects == subject, trial_mask
            )

            if np.sum(subject_specific_trial_mask) == 0:
                continue

            if mask is None:
                if handle_repetitions is None:
                    list_length = np.max(data["listLength"][trial_mask])
                    handle_repetitions = not (
                        presentations[trial_mask][:, :list_length]
                        == np.arange(list_length) + 1
                    ).all()

                if not handle_repetitions:
                    list_length = np.max(data["listLength"][trial_mask])
                    lag_range = list_length - 1
                    subject_crps.append(single_pres_crp(
                        trials[subject_specific_trial_mask], list_length
                    )[lag_range - max_lag : lag_range + max_lag + 1])
                else:
                    list_length = np.max(data["listLength"][trial_mask])
                    lag_range = list_length - 1
                    subject_crps.append(multi_pres_crp(
                        trials[subject_specific_trial_mask],
                        presentations[subject_specific_trial_mask],
                        list_length,
                    )[lag_range - max_lag : lag_range + max_lag + 1])
            else:
                list_length = np.max(data["presentations"][trial_mask])
                lag_range = list_length - 1
                subject_crps.append(masked_crp(
                    trials[subject_specific_trial_mask], list_length, mask
                    )[lag_range - max_lag : lag_range + max_lag + 1])

        subject_crps = np.array(subject_crps)
        subject_crps = np.delete(subject_crps, max_lag, axis=1)
        crp_mean = np.nanmean(subject_crps, axis=0)

        color=next(axis._get_lines.prop_cycler)['color']
        if len(subject_crps) > 1:
            errors = np.zeros((2, len(crp_mean)))
            with warnings.catch_warnings():
                warnings.simplefilter("ignore")
                bootstrapped_confidence_intervals = bootstrap(
                    (subject_crps,), np.nanmean
                ).confidence_interval
            errors[0] = crp_mean - bootstrapped_confidence_intervals.low
            errors[1] = bootstrapped_confidence_intervals.high - crp_mean

            # plot error bar using plt.fill_between and bootstrap
            axis.errorbar(lag_interval[:max_lag], crp_mean[:max_lag], errors[:, :max_lag], label=labels[data_index], color=color)
            axis.errorbar(lag_interval[max_lag+1:], crp_mean[max_lag:], errors[:, max_lag:], color=color)
        else:
            axis.plot(lag_interval[:max_lag], crp_mean[:max_lag], label=labels[data_index], color=color)
            axis.plot(lag_interval[max_lag+1:], crp_mean[max_lag:], color=color)

    axis.set(xlabel="Lag", ylabel="Conditional Resp. Prob.")

    if contrast_name:
        axis.legend(title=contrast_name)

    return axis

