import numpy as np
# from numba import njit

# @njit
def neighbor_contiguity(
    trials, # Integer array where rows correspond to trials and columns to recall positions. Non-zero values identify the first (1-indexed) study position of the item with that recall position.
    presentations, # Integer array where rows correspond to trials and columns to study positions. Non-zero values identify the unique index of the item presented at that position.
    max_repeats=2, # maximum times any item gets repeatedly presented in a trial
    min_lag=3 # minimum number of intervening items between study positions for a repeated item to be considered
    ):

    assert(len(presentations) == len(trials))
    assert(min_lag > 2)

    # 3D array tracking each presentation position of recalled item
    # shape is (repetition_index, trial_index, recall_position)
    terminus = np.sum(trials != 0, axis=1) # number of recalls per trial
    list_length = np.sum(presentations[0] != 0) # number of presentations in list
    total_possible_neighbor_transitions = 0
    total_actual_neighbor_transitions = 0

    # for each unique item presented in a trial, 
    # we compute a lag by identifying its first and second presentation positions
    # when a lag is greater than min_lag, we consider the item to be a repeated item
    # we seek out recalls of Si or Sj in corresponding trial recalls, then track the rate of transitions to Sj or Si
    for trial_index in range(len(trials)):

        # 1) track si and sj across repeated items in trial
        item_count = int(np.max(presentations[trial_index]))
        si = np.zeros((item_count, 2), dtype=np.int64)
        sj = np.zeros((item_count, 2), dtype=np.int64)

        for item in range(1, item_count+1):

            positions = np.nonzero(presentations[trial_index] == item)[0]
            if len(positions) > 1:
                lag = positions[1] - positions[0] - 1
            else:
                lag = -1

            if lag < min_lag:
                continue

            # as long as this never throws an error, 
            # we don't need special handling for when j occurs too late in list for sj to contain two items
            #assert np.all(positions < list_length - 2)
            si[item-1, :] = presentations[trial_index, positions[0]+1:positions[0]+3]
            sj[item-1, :] = presentations[trial_index, positions[1]+1:positions[1]+3]

        # 2) measure ratio of possible si/sj transitions to actual si/sj transitions across recall events in trial
        previous_item = 0
        possible_items = np.arange(item_count, dtype=np.int32)+1  # initial pool of possible recalls, 1-indexed
        for recall_index in range(terminus[trial_index]):

            current_item = presentations[trial_index][trials[trial_index, recall_index] - 1]
            
            if recall_index > 0:

                # if the previous item is in si or sj, we increment bins 
                # based on whether current item is in corresponding subset of sj or si
                possible_count = 0
                actual_count = 0

                si_match = np.nonzero(si == previous_item)[0]
                if len(si_match) > 0:
                    for possible_item in possible_items:
                        if possible_item in sj[si_match]:
                            possible_count += 1
                    if current_item in sj[si_match]:
                        actual_count += 1

                total_actual_neighbor_transitions += actual_count > 0

                actual_count = 0

                sj_match = np.nonzero(sj == previous_item)[0]
                if len(sj_match) > 0:
                    for possible_item in possible_items:
                        if possible_item in si[sj_match]:
                            possible_count += 1
                    if current_item in si[sj_match]:
                        actual_count += 1

                #assert(actual_count < 2)
                #assert(possible_count < 2)
                total_possible_neighbor_transitions += possible_count > 0
                total_actual_neighbor_transitions += actual_count > 0

            # update pool to exclude recalled item (updated to still identify 1-indexed item)
            previous_item = current_item
            possible_items = possible_items[possible_items != previous_item]

    return total_actual_neighbor_transitions / total_possible_neighbor_transitions

# %% ../src/analyses/Neighbor_Contiguity.ipynb 7
import matplotlib.pyplot as plt
from scipy.stats import bootstrap
import warnings

def plot_neighbor_contiguity(
    datasets, # sequence dataset structures to plot
    trial_masks, # vectors to filter datasets by for main analysis
    control_trial_masks=None, # vectors to filter datasets by for control analysis
    labels=None, # sequence of names for each dataset to use in the legend
    contrast_name=None, # name of the contrast to use in the legend
    axis=None, # `matplotlib` axis object to plot on
    control_recalls = None,
    control_experiment_count = 0,
    ):

    if axis is None:
        plt.figure()
        axis = plt.gca()

    if labels is None:
        labels = [''] * len(datasets)

    for data_index, data in enumerate(datasets):

        trial_mask = trial_masks[data_index]
        control_trial_mask = control_trial_masks[data_index]
        trials = data['recalls']
        list_length = np.max(data['listLength'][trial_mask])
        presentations = data['pres_itemnos'][:, :list_length]
        subjects = data["subject"].flatten()
        subject_ncs = [] #np.zeros((len(np.unique(subjects)), 1))
        subject_ctrl_ncs = [] #np.zeros((len(np.unique(subjects)), 1))

        for subject_index, subject in enumerate(np.unique(subjects)):
            subject_specific_trial_mask = np.logical_and(
                subjects == subject, trial_mask
            )
            ctrl_subject_specific_trial_mask = np.logical_and(
                subjects == subject, control_trial_mask
            )

            if np.sum(subject_specific_trial_mask) == 0:
                continue

            subject_ncs.append(neighbor_contiguity(trials[subject_specific_trial_mask], presentations[subject_specific_trial_mask]))

            results = []
            indices = np.arange(np.sum(ctrl_subject_specific_trial_mask))
            for i in range(100):
                np.random.shuffle(indices)
                try:
                    results.append(neighbor_contiguity(trials[ctrl_subject_specific_trial_mask][indices], presentations[subject_specific_trial_mask]))
                except ZeroDivisionError:
                    pass

            subject_ctrl_ncs.append(np.mean(results))

        subject_ncs = np.array(subject_ncs)
        nc_mean = np.mean(subject_ncs, axis=0)
        subject_ctrl_ncs = np.array(subject_ctrl_ncs)
        ctrl_nc_mean = np.mean(subject_ctrl_ncs, axis=0)

        if len(subject_ncs) > 1:
            errors = errors = np.zeros((2, 2))
            with warnings.catch_warnings():
                warnings.simplefilter("ignore")
                bootstrapped_confidence_intervals = bootstrap((subject_ncs,), np.mean).confidence_interval 
            errors[0, 0] = nc_mean - bootstrapped_confidence_intervals.low
            errors[1, 0] = bootstrapped_confidence_intervals.high - nc_mean

            with warnings.catch_warnings():
                warnings.simplefilter("ignore")
                bootstrapped_confidence_intervals = bootstrap((subject_ctrl_ncs,), np.mean).confidence_interval 
            errors[0, 1] = ctrl_nc_mean - bootstrapped_confidence_intervals.low
            errors[1, 1] = bootstrapped_confidence_intervals.high - ctrl_nc_mean

            # plot error bar using plt.fill_between and bootstrap
            axis.errorbar(np.arange(2), [nc_mean, ctrl_nc_mean], errors, label=labels[data_index], ls='none', fmt='.', elinewidth=4, mew=5)

        else:
            axis.plot(np.arange(2), [nc_mean, ctrl_nc_mean], label=labels[data_index], ls='none', marker='.', markersize=10)
            
    axis.set_xticks(np.arange(2, dtype=np.int32)) 
