import numpy as np
# from numba import njit

# @njit(nogil=True)
def single_pres_pfr(
    recalls, # Integer array where rows correspond to trials and columns to recall positions. Non-zero values are the (1-indexed) single study position of the item recalled at that position.
    list_length # Number of item presentations in each study sequence
    ):
    """
    Assuming each study sequence has no more than a single presentation of each item, returns a vector of length `list_length` containing the recall rate by serial position across all provided `trials`.
    """
    return np.bincount(recalls[:, 0], minlength=list_length+1)[1:]/len(recalls)

# %% ../src/analyses/Probability_of_First_Recall.ipynb 5
# @njit(nogil=True)
def multi_pres_pfr(
    recalls, # Integer array where rows correspond to trials and columns to recall positions. Non-zero values identify a (1-indexed) study position of the item recalled at that position.
    presentations, # Integer array where rows correspond to trials and columns to study positions. Non-zero values identify the unique index of the item presented at that position.
    list_length # Number of item presentations in each study sequence
    ):
    """
    Calculate recall rate by serial position across trials without the assumption that each study sequence has no more than a single presentation of each item.

    This function is slower than `single_pres_spc`, but it can be used with data where the single presentation assumption does not hold.
    """

    result = np.zeros(list_length, dtype=np.int32)
    all_study_positions = recall_by_all_study_positions(recalls, presentations) 
    first_recalls = all_study_positions[:, :, :1]
    
    for trial_index in range(len(recalls)):
        for study_position in range(list_length):
            result[study_position] += study_position+1 in first_recalls[:,trial_index]
    
    return result/len(recalls)

