# @njit(nogil=True)
def single_pres_spc(
    recalls, # Integer array where rows correspond to trials and columns to recall positions. Non-zero values are the (1-indexed) single study position of the item recalled at that position.
    list_length # Number of item presentations in each study sequence
    ):
    """
    Assuming each study sequence has no more than a single presentation of each item, returns a vector of length `list_length` containing the recall rate by serial position across all provided `recalls`. This function can track occurrence rates by many other features if non-zero values in `recalls` are replaced with the appropriate feature index.
    """

    # flatten provided recalls matrix and count proportion of recalls at each index, ignoring index 0
    return np.bincount(recalls.flatten(), minlength=list_length+1)[1:]/len(recalls)

