# from numba import njit, prange
import numpy as np

# @njit(nogil=True, parallel=True)
def recall_probability_by_lag(
    recalls, # Integer array where rows correspond to trials and columns to recall positions. Non-zero values identify the first (1-indexed) study position of the item with that recall position.
    presentations, # Integer array where rows correspond to trials and columns to study positions. Non-zero values identify the unique index of the item presented at that position.
    max_lag=8 # maximum possible number of intervening items between repetitions
    ):
    
    assert(len(presentations) == len(recalls))
    total_presented, total_retrieved = np.zeros(max_lag+2), np.zeros(max_lag+2)

    # for each unique item presented in a trial, 
    # we compute a lag by identifying its first and second presentation positions
    # then increment the corresponding lag bins in the presented and retrieved vectors
    for trial_index in range(len(presentations)):
        presented, retrieved = np.zeros(max_lag+2), np.zeros(max_lag+2)
        trial = recalls[trial_index]
        trial = trial[trial > 0]-1
        
        for item in np.unique(presentations[trial_index]):
            if item == 0:
                continue

            positions = np.nonzero(presentations[trial_index] == item)[0]
            if len(positions) > 1:
                lag = positions[1] - positions[0] - 1
            else:
                lag = -1

            presented[lag+1] += 1 # we correct indices to be non-negative
            retrieved[lag+1] += positions[0] in trial
            
        total_presented += presented
        total_retrieved += retrieved

    return total_retrieved/total_presented

# %% ../src/analyses/Spacing_Effect.ipynb 5
# @njit(nogil=True, parallel=True)
def find_max_lag(
    presentations, # Integer array where rows correspond to trials and columns to study positions. Non-zero values identify the unique index of the item presented at that position.
    ):
    """
    Finds the maximum lag between repetitions of any item in the dataset.
    """

    max_lag = -1
    for trial_index in range(len(presentations)):
        for item in np.unique(presentations[trial_index]):
            if item == 0:
                continue

            for idx, val in np.ndenumerate(presentations[trial_index]):
                if val == item:
                    first_study_position = idx[0]
                    break

            lag = -1 # lag of -1 means the item was not repeated
            if first_study_position < len(presentations[trial_index]):
                for idx, val in np.ndenumerate(presentations[trial_index][first_study_position+1:]):
                    if val == item:
                        lag = idx[0]
                        break

            max_lag = max(max_lag, lag)

    return max(max_lag, -1)

